public class Pizza {
    private final String size, crust;
    private final boolean cheese, pepperoni;

    private Pizza(Builder b) {
        size = b.size; crust = b.crust;
        cheese = b.cheese; pepperoni = b.pepperoni;
    }

    public String toString() {
        return size + "/" + crust + " cheese=" + cheese + " pep=" + pepperoni;
    }

    static class Builder {
        String size, crust = "thin";
        boolean cheese, pepperoni;
        Builder(String size) { this.size = size; }
        Builder crust(String c)  { crust = c;        return this; }
        Builder cheese()         { cheese = true;     return this; }
        Builder pepperoni()      { pepperoni = true;  return this; }
        Pizza build()            { return new Pizza(this); }
    }

    public static void main(String[] args) {
        Pizza p1 = new Pizza.Builder("large").crust("thick").cheese().pepperoni().build();
        Pizza p2 = new Pizza.Builder("small").build();
        System.out.println(p1);
        System.out.println(p2);
    }
}
